import{_ as r,c as o,o as s,ag as n}from"./chunks/framework.XjE0kKti.js";const g="/gatewayweb/docs/assets/hub0061-static-service-list.CgyTdkbi.png",a="/gatewayweb/docs/assets/hub0061-static-service-context-menu.BJXcLtmb.png",d="/gatewayweb/docs/assets/hub0061-static-node-add-dialog.CmA6tUWS.png",m=JSON.parse('{"title":"静态映射（hub0061）","description":"","frontmatter":{},"headers":[],"relativePath":"modules/hub0061.md","filePath":"modules/hub0061.md","lastUpdated":1776841524000}'),e={name:"modules/hub0061.md"};function h(l,t,i,b,c,u){return s(),o("div",null,[...t[0]||(t[0]=[n('<h1 id="静态映射-hub0061" tabindex="-1">静态映射（hub0061） <a class="header-anchor" href="#静态映射-hub0061" aria-label="Permalink to &quot;静态映射（hub0061）&quot;">​</a></h1><p>维护 <strong>静态代理服务</strong>（在指定监听地址上接受连接，并按负载均衡策略转发到多个 <strong>后端节点</strong>），并查看运行态的连接数与流量汇总。支持服务的生命周期操作（启动、停止、重载配置、删除）、配置弹窗维护，以及在某服务下管理 <strong>静态节点</strong>（后端目标地址与端口等）。</p><p><img src="'+g+'" alt="静态服务列表、统计与筛选"></p><hr><h2 id="概述" tabindex="-1">概述 <a class="header-anchor" href="#概述" aria-label="Permalink to &quot;概述&quot;">​</a></h2><table tabindex="0"><thead><tr><th>能力</th><th>说明</th></tr></thead><tbody><tr><td>服务列表</td><td>按名称、监听地址、类型、状态筛选；分页列表展示连接与流量等指标。</td></tr><tr><td>统计卡片</td><td>总服务数、运行中、已停止、总连接数、接收/发送流量汇总（在 <strong>查询</strong> 成功后随列表一并刷新）。</td></tr><tr><td>工具栏</td><td><strong>新增服务</strong>；<strong>启动 / 停止 / 重载 / 删除</strong> 均针对 <strong>一条</strong> 目标服务（勾选优先，无勾选时用当前点击行）。</td></tr><tr><td>行内与右键</td><td><strong>节点数</strong> 列可点击打开「静态节点管理」弹窗；表格 <strong>状态</strong> 列为启用开关；右键提供查看、编辑、管理节点、启停与重载等。</td></tr><tr><td>节点子页</td><td>在节点弹窗内维护该服务下的后端节点（新增、删除、查看/编辑、行内启停）。</td></tr></tbody></table><hr><h2 id="访问入口" tabindex="-1">访问入口 <a class="header-anchor" href="#访问入口" aria-label="Permalink to &quot;访问入口&quot;">​</a></h2><p>侧栏 <strong>隧道管理</strong> → <strong>静态映射</strong>。</p><hr><h2 id="加载说明" tabindex="-1">加载说明 <a class="header-anchor" href="#加载说明" aria-label="Permalink to &quot;加载说明&quot;">​</a></h2><p>页面打开后需点击 <strong>查询</strong> 才会请求服务列表；同时会刷新顶部 <strong>统计卡片</strong>。<strong>重置</strong> 清空筛选条件后再查询。</p><hr><h2 id="筛选条件" tabindex="-1">筛选条件 <a class="header-anchor" href="#筛选条件" aria-label="Permalink to &quot;筛选条件&quot;">​</a></h2><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>服务名称</strong></td><td>占位：请输入服务名称。</td></tr><tr><td><strong>监听地址</strong></td><td>占位：请输入监听地址（可与列表中「监听 IP:端口」对照）。</td></tr><tr><td><strong>服务类型</strong></td><td>全部 / <strong>TCP</strong> / <strong>UDP</strong>。</td></tr><tr><td><strong>服务状态</strong></td><td>全部 / <strong>运行中</strong> / <strong>已停止</strong> / <strong>错误</strong>。</td></tr></tbody></table><hr><h2 id="工具栏-服务" tabindex="-1">工具栏（服务） <a class="header-anchor" href="#工具栏-服务" aria-label="Permalink to &quot;工具栏（服务）&quot;">​</a></h2><table tabindex="0"><thead><tr><th>按钮</th><th>说明</th></tr></thead><tbody><tr><td><strong>新增服务</strong></td><td>打开「新增静态服务」多 Tab 表单弹窗。</td></tr><tr><td><strong>启动</strong></td><td>取 <strong>已勾选行</strong>；若无勾选，则取 <strong>当前高亮（点击）行</strong>。未选中时提示先选择。</td></tr><tr><td><strong>停止</strong></td><td>同上，一条服务。</td></tr><tr><td><strong>重载</strong></td><td>同上，对该服务重载运行时配置。</td></tr><tr><td><strong>删除</strong></td><td>同上，删除 <strong>一条</strong> 服务（确认后执行）。</td></tr><tr><td><strong>查询</strong> / <strong>重置</strong></td><td>与筛选表单联动。</td></tr></tbody></table><hr><h2 id="统计卡片" tabindex="-1">统计卡片 <a class="header-anchor" href="#统计卡片" aria-label="Permalink to &quot;统计卡片&quot;">​</a></h2><p>共六项：<strong>总服务数</strong>、<strong>运行中</strong>、<strong>已停止</strong>、<strong>总连接数</strong>、<strong>接收流量</strong>、<strong>发送流量</strong>（流量按字节格式化展示，无数据时多为 <code>0 B</code>）。</p><hr><h2 id="服务表格列-主要" tabindex="-1">服务表格列（主要） <a class="header-anchor" href="#服务表格列-主要" aria-label="Permalink to &quot;服务表格列（主要）&quot;">​</a></h2><p>含左侧 <strong>勾选</strong> 与 <strong>序号</strong>。数据列包括：<strong>服务名称</strong>、<strong>监听地址</strong>（监听 IP 与监听端口拼接展示）、<strong>服务类型</strong>（TCP/UDP 标签）、<strong>服务状态</strong>（运行中 / 已停止 / 错误）、<strong>节点数</strong>（可点击文案如「N 个节点」打开节点管理）、<strong>当前连接</strong>、<strong>总连接数</strong>、<strong>接收流量</strong>、<strong>发送流量</strong>、<strong>负载均衡</strong>（轮询 / 最少连接 / 随机 等文案）、<strong>最大连接</strong>、<strong>状态</strong>（启用开关，切换会调用更新接口）、<strong>描述</strong>、<strong>启动时间</strong>、<strong>创建时间</strong> 等；底部分页。</p><hr><h2 id="服务表单弹窗-新增-编辑-查看" tabindex="-1">服务表单弹窗（新增 / 编辑 / 查看） <a class="header-anchor" href="#服务表单弹窗-新增-编辑-查看" aria-label="Permalink to &quot;服务表单弹窗（新增 / 编辑 / 查看）&quot;">​</a></h2><p>标题随模式为 <strong>新增静态服务</strong>、<strong>编辑静态服务</strong>、<strong>查看静态服务详情</strong>。可见 Tab 主要包括：</p><ul><li><strong>基本信息</strong>：服务名称、服务类型、监听地址与监听端口、启用状态、服务描述等。</li><li><strong>网络配置</strong>：如连接超时等（部分表单项在代码中因后端未对接而隐藏，以界面为准）。</li><li><strong>负载均衡</strong>：负载均衡类型、健康检查类型与 URL、检查间隔与超时等（健康检查相关字段会随类型联动显示）。</li><li><strong>其他信息</strong>：备注及创建/修改只读字段等。</li></ul><p>其中 <strong>TLS 配置</strong> Tab 在模型中默认隐藏（后端暂未实现 TLS 时前端不展示）。</p><hr><h2 id="右键菜单-服务" tabindex="-1">右键菜单（服务） <a class="header-anchor" href="#右键菜单-服务" aria-label="Permalink to &quot;右键菜单（服务）&quot;">​</a></h2><p><img src="'+a+'" alt="服务列表右键菜单"></p><table tabindex="0"><thead><tr><th>菜单项</th><th>说明</th></tr></thead><tbody><tr><td><strong>复制行数据</strong> / <strong>复制单元格</strong></td><td>表格内置。</td></tr><tr><td><strong>查看详情</strong></td><td>只读打开服务表单。</td></tr><tr><td><strong>编辑</strong></td><td>拉取详情后进入编辑。</td></tr><tr><td><strong>管理节点</strong></td><td>打开 <strong>静态节点管理</strong> 弹窗（与点击「节点数」列效果一致）。</td></tr><tr><td><strong>启动</strong> / <strong>停止</strong> / <strong>重载配置</strong> / <strong>删除</strong></td><td>针对当前行，删除与生命周期类操作一般会二次确认。</td></tr></tbody></table><hr><h2 id="静态节点管理-弹窗" tabindex="-1">静态节点管理（弹窗） <a class="header-anchor" href="#静态节点管理-弹窗" aria-label="Permalink to &quot;静态节点管理（弹窗）&quot;">​</a></h2><p>从服务的 <strong>节点数</strong> 列或右键 <strong>管理节点</strong> 进入。标题默认为 <strong>静态节点管理 -</strong> 后跟当前 <strong>服务名称</strong>。</p><h3 id="筛选与工具栏" tabindex="-1">筛选与工具栏 <a class="header-anchor" href="#筛选与工具栏" aria-label="Permalink to &quot;筛选与工具栏&quot;">​</a></h3><ul><li>筛选项：<strong>节点名称</strong>、<strong>目标地址</strong>、<strong>节点状态</strong>、<strong>健康状态</strong>（选项与列表数据一致即可）。</li><li><strong>新增节点</strong>：打开下方节点表单。</li><li><strong>删除</strong>：使用表格 <strong>当前高亮行</strong>（<code>getCurrentRecord</code>）：需先 <strong>单击</strong> 选中一行再点删除；<strong>非</strong> 按多选勾选批量删除（与工具栏 tooltip 文案可能不一致时，以实际交互为准）。</li><li><strong>查询</strong> / <strong>重置</strong>：刷新节点分页列表。</li></ul><h3 id="节点表格" tabindex="-1">节点表格 <a class="header-anchor" href="#节点表格" aria-label="Permalink to &quot;节点表格&quot;">​</a></h3><p>含勾选列与序号，列包括：<strong>节点名称</strong>、<strong>目标地址</strong>、<strong>目标端口</strong>、<strong>代理类型</strong>、<strong>节点状态</strong>、<strong>健康状态</strong>、<strong>当前连接</strong>、<strong>总连接数</strong>、<strong>接收/发送流量</strong>、<strong>失败次数</strong>、<strong>最后检查</strong>、行内 <strong>状态</strong> 开关、<strong>描述</strong>、<strong>创建时间</strong> 等。</p><p>右键菜单：<strong>查看详情</strong>、<strong>编辑</strong>、<strong>删除</strong>；并含复制行等内置项。</p><h3 id="新增-编辑节点表单" tabindex="-1">新增 / 编辑节点表单 <a class="header-anchor" href="#新增-编辑节点表单" aria-label="Permalink to &quot;新增 / 编辑节点表单&quot;">​</a></h3><p><img src="'+d+'" alt="新增静态节点表单（基本信息）"></p><p>弹窗标题为 <strong>新增静态节点</strong> / <strong>编辑静态节点</strong> / <strong>查看静态节点详情</strong>。默认可见 Tab 为 <strong>基本信息</strong> 与 <strong>其他信息</strong>（<strong>高级配置</strong> Tab 在模型中默认隐藏）。</p><p><strong>基本信息</strong> 中常见字段：</p><table tabindex="0"><thead><tr><th>字段</th><th>说明</th></tr></thead><tbody><tr><td><strong>节点名称</strong></td><td>必填。</td></tr><tr><td><strong>目标地址</strong></td><td>必填，后端 IP 或域名。</td></tr><tr><td><strong>目标端口</strong></td><td>必填，数字，默认 <strong>80</strong>。</td></tr><tr><td><strong>代理类型</strong></td><td>必填，默认 <strong>TCP</strong>（与 UDP 等选项一致）。</td></tr><tr><td><strong>启用状态</strong></td><td>开关，默认启用（<code>Y</code>/<code>N</code>）。</td></tr><tr><td><strong>节点描述</strong></td><td>可选，多行，最多 <strong>500</strong> 字。</td></tr></tbody></table><p>保存成功后关闭弹窗并刷新节点列表；父页面会在弹窗关闭/刷新回调中同步刷新服务列表与统计（以实际接口为准）。</p><hr><h2 id="与隧道服务器-hub0060-的关系" tabindex="-1">与隧道服务器（hub0060）的关系 <a class="header-anchor" href="#与隧道服务器-hub0060-的关系" aria-label="Permalink to &quot;与隧道服务器（hub0060）的关系&quot;">​</a></h2><p><strong>hub0060</strong> 管理隧道路由 <strong>服务端进程</strong> 与注册视图；<strong>hub0061</strong> 管理的是 <strong>静态代理服务及其后端节点</strong>，用于入口监听与多目标负载均衡，二者职责不同，可按部署架构组合使用。</p>',50)])])}const q=r(e,[["render",h]]);export{m as __pageData,q as default};
